files.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg: #ffffff;
  --fg: #0d0d0d;
  --ruler-bg: #f5f5f5;
  --ruler-border: #e0e0e0;
  --ruler-tick: #cccccc;
  --ruler-text: #bbbbbb;
  --ruler-active-tick: #888888;
  --ruler-active-text: #333333;
}

[data-theme="dark"] {
  --bg: #0d0d0d;
  --fg: #ffffff;
  --ruler-bg: #0d0d0d;
  --ruler-border: #252525;
  --ruler-tick: #2a2a2a;
  --ruler-text: #3a3a3a;
  --ruler-active-tick: #555555;
  --ruler-active-text: #aaaaaa;
}

html, body {
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
}

body {
  background: var(--bg);
  color: var(--fg);
}

.theme-bg {
  background: var(--bg);
}

* {
  box-sizing: border-box;
}

.theme-toggle-wrap {
  transition: background 0.15s ease;
}

.theme-toggle-wrap:hover {
  background: rgba(128, 128, 128, 0.08);
}

.toggle-icon {
  display: inline-flex;
  position: relative;
  width: 16px;
  height: 16px;
}

.toggle-icon .icon-a,
.toggle-icon .icon-b {
  position: absolute;
  inset: 0;
  display: inline-flex;
}

.toggle-icon .icon-a {
  transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.4s ease;
  transform: rotate(0deg) scale(1);
  opacity: 1;
}

.toggle-icon .icon-b {
  transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.4s ease;
  transform: rotate(-180deg) scale(0);
  opacity: 0;
}

.theme-toggle-wrap:hover .icon-a {
  transform: rotate(180deg) scale(0);
  opacity: 0;
}

.theme-toggle-wrap:hover .icon-b {
  transform: rotate(0deg) scale(1);
  opacity: 1;
}

@keyframes trace-border {
  from { stroke-dashoffset: 140; }
  to { stroke-dashoffset: 0; }
}

@keyframes trace-border-reverse {
  from { stroke-dashoffset: 0; }
  to { stroke-dashoffset: 140; }
}

.orbit-dots {
  opacity: 0;
  transition: opacity 0.1s ease;
}

.orbit-dots.active {
  opacity: 1;
  animation: orbit-spin 600ms linear;
}

.orbit-dots:not(.active) {
  animation: none;
}

@keyframes orbit-spin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.orbit-dot {
  position: absolute;
  width: 2px;
  height: 2px;
  border-radius: 50%;
  background: currentColor;
  opacity: 0.5;
}
